//! Fanout primitive IR + per-target codegen.
//!
//! Task #8: generalize the FOIL `fork` primitive into a single `fanout(N, op,
//! combiner)` IR node. Each existing five-force primitive becomes
//! `fanout + combiner`:
//!
//! | primitive  | combiner            | Wankel/Lean anchor                                |
//! |------------|---------------------|---------------------------------------------------|
//! | fork       | `Combiner::Collect` | `WankelEngineTheorem.wankel_phase_lifecycle_stage .intake` |
//! | race       | `Combiner::First`   | `WankelEngineTheorem.wankel_phase_lifecycle_stage .compression` |
//! | fold       | `Combiner::Reduce`  | `WankelEngineTheorem.wankel_phase_lifecycle_stage .ignition` |
//! | vent       | `Combiner::Drop`    | `WankelEngineTheorem.wankel_phase_lifecycle_stage .exhaust` |
//! | interfere  | `Combiner::Mix`     | `WankelEngineTheorem.ignition_contact` (chirality-weighted) |
//!
//! Task #18: lower the same IR into idiomatic source for each supported target
//! language. The lowering carries Stoplight phase metadata so a downstream
//! runtime can phase-align (port of `foil-runtime/foil-stoplight.ts`'s
//! `Combiners` namespace).
//!
//! Correctness property (verified by `tests/fanout_correctness.rs`): given the
//! same `Fanout { n, op, combiner }` and the same seeded input set, every
//! supported target emits source that, when executed, yields the same
//! *combiner-projected* result. We do not execute foreign toolchains here; the
//! test runs the Rust reference implementation and asserts each target's
//! emitted source contains the structural markers that the runtime contract
//! requires (combiner verb, fanout cardinality, stoplight metadata).

use std::collections::BTreeMap;

/// Reduction kernels supported by `Combiner::Reduce`.
///
/// Kept deliberately small so every target can implement the same set without
/// pulling in standard-library divergences. Numeric reductions only -- the
/// `Combiner::Reduce` semantics are defined on `i64` payloads to keep the
/// cross-language correctness contract finite.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum ReduceKernel {
    /// Additive fold: `acc + x`. Identity = 0.
    Sum,
    /// Multiplicative fold: `acc * x`. Identity = 1.
    Product,
    /// Lattice meet: `min(acc, x)`. Identity = i64::MAX.
    Min,
    /// Lattice join: `max(acc, x)`. Identity = i64::MIN.
    Max,
}

impl ReduceKernel {
    pub fn identity(self) -> i64 {
        match self {
            ReduceKernel::Sum => 0,
            ReduceKernel::Product => 1,
            ReduceKernel::Min => i64::MAX,
            ReduceKernel::Max => i64::MIN,
        }
    }

    pub fn apply(self, acc: i64, x: i64) -> i64 {
        match self {
            ReduceKernel::Sum => acc.wrapping_add(x),
            ReduceKernel::Product => acc.wrapping_mul(x),
            ReduceKernel::Min => acc.min(x),
            ReduceKernel::Max => acc.max(x),
        }
    }

    /// Canonical verb the codegen prints into emitted source. Lets the test
    /// harness assert the right combiner shape per target.
    pub fn verb(self) -> &'static str {
        match self {
            ReduceKernel::Sum => "sum",
            ReduceKernel::Product => "product",
            ReduceKernel::Min => "min",
            ReduceKernel::Max => "max",
        }
    }
}

/// The five FOIL primitives expressed as combiner choices over a single
/// `fanout` IR node.
///
/// Each variant cites its anchor theorem in `gnosis-math/Gnosis/WankelEngineTheorem.lean`
/// so the Lean lifecycle and the Rust IR stay in lock-step.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Combiner {
    /// `fork = fanout + collect`.
    ///
    /// Returns the ordered vector of every branch result.
    ///
    /// Lean: `WankelEngineTheorem.wankel_phase_lifecycle_stage .intake = .fork`.
    Collect,

    /// `race = fanout + first`.
    ///
    /// Returns the first branch result (deterministic in the IR: lowest input
    /// index; runtimes that race wall-clock pick whichever resolves first, but
    /// the correctness invariant compares against the set-equality projection).
    ///
    /// Lean: `WankelEngineTheorem.wankel_phase_lifecycle_stage .compression = .race`.
    First,

    /// `fold = fanout + reduce` with kernel `k`.
    ///
    /// Lean: `WankelEngineTheorem.wankel_phase_lifecycle_stage .ignition = .fold`;
    /// the kernel choice is the algebraic shape supplied to `Foldable` in the
    /// fifth-force lifecycle.
    Reduce(ReduceKernel),

    /// `vent = fanout + drop` -- keep at most `keep` results, discard the tail.
    ///
    /// Lean: `WankelEngineTheorem.wankel_phase_lifecycle_stage .exhaust = .vent`
    /// (`exhaust_contact_is_bounded`).
    Drop { keep: usize },

    /// `interfere = fanout + chirality-weighted mix`.
    ///
    /// Computes `sum_i (results[i] * weights[i]) / sum_i weights[i]` in i64
    /// arithmetic (sum-of-weights guarded against zero -> identity 0).
    ///
    /// Lean: `WankelEngineTheorem.ignition_contact` (the interference contact
    /// theorem) and `InterferenceAsTheFifthForce.constructive_interference`.
    Mix { weights: Vec<i64> },
}

impl Combiner {
    /// Canonical verb printed by every target so the test can scan for the
    /// combiner shape without parsing the foreign language.
    pub fn verb(&self) -> &'static str {
        match self {
            Combiner::Collect => "collect",
            Combiner::First => "first",
            Combiner::Reduce(_) => "reduce",
            Combiner::Drop { .. } => "drop",
            Combiner::Mix { .. } => "mix",
        }
    }

    /// Cite the Lean theorem this combiner formalizes -- emitted into the
    /// generated source as a comment so a grep over the lowered file recovers
    /// the proof anchor.
    pub fn lean_anchor(&self) -> &'static str {
        match self {
            Combiner::Collect => "WankelEngineTheorem.wankel_phase_lifecycle_stage .intake",
            Combiner::First => "WankelEngineTheorem.wankel_phase_lifecycle_stage .compression",
            Combiner::Reduce(_) => "WankelEngineTheorem.wankel_phase_lifecycle_stage .ignition",
            Combiner::Drop { .. } => "WankelEngineTheorem.exhaust_contact_is_bounded",
            Combiner::Mix { .. } => "WankelEngineTheorem.ignition_contact",
        }
    }
}

/// Optional Stoplight metadata travels with a fanout so a runtime can
/// phase-align tasks. Mirrors `foil-runtime/foil-stoplight.ts::Stoplight`.
///
/// Codegen emits this as structured comments alongside the fanout. Runtimes
/// that honor it sleep tasks to their per-branch green window. Runtimes that
/// ignore it still execute correctly -- the metadata is informational, not
/// load-bearing for correctness.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct Stoplight {
    pub cycle: u32,
    pub green: u32,
    pub offset: u32,
    pub distance: u32,
    pub speed: u32,
}

impl Stoplight {
    pub fn travel_time(&self) -> u32 {
        if self.speed == 0 {
            0
        } else {
            self.distance / self.speed
        }
    }
}

/// Chirality marker -- `+1` for outgoing wave, `-1` for return echo. Mirrors
/// `WankelEngineTheorem.forwardWave` / `returnEcho` polarity.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Chirality {
    Forward,
    Return,
}

impl Chirality {
    pub fn marker(self) -> i32 {
        match self {
            Chirality::Forward => 1,
            Chirality::Return => -1,
        }
    }
}

/// The fanout IR node.
///
/// `op` is the symbolic name of the per-branch operation (e.g. `load_user`).
/// Each target lowering wraps that op so the same name resolves to a callable
/// in the target language. The test harness uses a stub op that returns the
/// branch index so output equality is verifiable without dynamic-linking
/// foreign code.
#[derive(Debug, Clone)]
pub struct Fanout {
    /// Branch count.
    pub n: usize,
    /// Symbolic op name -- target codegen must produce a callable with this
    /// identifier in its emitted scope.
    pub op: String,
    /// Combiner selection -- chooses which FOIL primitive this fanout reduces
    /// to (fork/race/fold/vent/interfere).
    pub combiner: Combiner,
    /// Optional Stoplight phase metadata per branch. Empty = no phase
    /// alignment. Codegen accepts `len == n` or `len == 0`.
    pub stoplights: Vec<Stoplight>,
    /// Optional per-branch chirality (forward/return) so a runtime can route
    /// interference correctly. Empty = all forward.
    pub chirality: Vec<Chirality>,
}

impl Fanout {
    /// Construct the canonical `fork` fanout: collect every result.
    pub fn fork(n: usize, op: impl Into<String>) -> Self {
        Self::new(n, op, Combiner::Collect)
    }

    /// Construct a `race` fanout: take the first result.
    pub fn race(n: usize, op: impl Into<String>) -> Self {
        Self::new(n, op, Combiner::First)
    }

    /// Construct a `fold` fanout with the given reduction kernel.
    pub fn fold(n: usize, op: impl Into<String>, kernel: ReduceKernel) -> Self {
        Self::new(n, op, Combiner::Reduce(kernel))
    }

    /// Construct a `vent` fanout that keeps the first `keep` results.
    pub fn vent(n: usize, op: impl Into<String>, keep: usize) -> Self {
        Self::new(n, op, Combiner::Drop { keep })
    }

    /// Construct an `interfere` fanout with chirality-weighted mix weights.
    pub fn interfere(n: usize, op: impl Into<String>, weights: Vec<i64>) -> Self {
        Self::new(n, op, Combiner::Mix { weights })
    }

    pub fn new(n: usize, op: impl Into<String>, combiner: Combiner) -> Self {
        Self {
            n,
            op: op.into(),
            combiner,
            stoplights: Vec::new(),
            chirality: Vec::new(),
        }
    }

    pub fn with_stoplights(mut self, lights: Vec<Stoplight>) -> Self {
        self.stoplights = lights;
        self
    }

    pub fn with_chirality(mut self, c: Vec<Chirality>) -> Self {
        self.chirality = c;
        self
    }
}

// =============================================================================
// Reference combiner -- the cross-language correctness oracle.
// =============================================================================

/// The combiner projection over a concrete result vector. Every target's
/// emitted source must compute a value that compares set-equal to this for the
/// same `(n, op, combiner)` triple under the test's stub op (which returns the
/// branch index `i: i64`).
pub fn apply_combiner(combiner: &Combiner, results: &[i64]) -> Vec<i64> {
    match combiner {
        Combiner::Collect => results.to_vec(),
        Combiner::First => results.iter().next().copied().into_iter().collect(),
        Combiner::Reduce(k) => {
            let acc = results.iter().fold(k.identity(), |acc, x| k.apply(acc, *x));
            // If the input is empty, return the identity. Otherwise return the
            // fold. (Identity is the algebraically-correct empty-fold answer.)
            vec![acc]
        }
        Combiner::Drop { keep } => results.iter().take(*keep).copied().collect(),
        Combiner::Mix { weights } => {
            let sum_w: i64 = weights.iter().sum();
            if sum_w == 0 {
                return vec![0];
            }
            let acc: i128 = results
                .iter()
                .zip(weights.iter())
                .map(|(r, w)| (*r as i128) * (*w as i128))
                .sum();
            vec![(acc / sum_w as i128) as i64]
        }
    }
}

// =============================================================================
// Per-target codegen.
// =============================================================================

/// All supported codegen targets. The crate ships ≥5 first-class targets per
/// task #18's definition of done; additional targets can register without
/// breaking the contract because the IR + correctness oracle are target-
/// agnostic.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum Target {
    Rust,
    JavaScript,
    Elixir,
    Go,
    Python,
}

impl Target {
    pub fn name(self) -> &'static str {
        match self {
            Target::Rust => "rust",
            Target::JavaScript => "javascript",
            Target::Elixir => "elixir",
            Target::Go => "go",
            Target::Python => "python",
        }
    }

    pub fn extension(self) -> &'static str {
        match self {
            Target::Rust => "rs",
            Target::JavaScript => "js",
            Target::Elixir => "exs",
            Target::Go => "go",
            Target::Python => "py",
        }
    }

    pub fn all() -> &'static [Target] {
        &[
            Target::Rust,
            Target::JavaScript,
            Target::Elixir,
            Target::Go,
            Target::Python,
        ]
    }
}

/// Lower a fanout IR node into idiomatic target source. Each emitted module
/// exposes a single `fanout_<verb>` entry point that takes a per-branch input
/// function (matching the symbolic `op` name in `fan.op`) and returns the
/// combiner-projected result.
pub fn lower(fan: &Fanout, target: Target) -> String {
    match target {
        Target::Rust => lower_rust(fan),
        Target::JavaScript => lower_javascript(fan),
        Target::Elixir => lower_elixir(fan),
        Target::Go => lower_go(fan),
        Target::Python => lower_python(fan),
    }
}

/// Render a one-target lowering plus a structured header that every target
/// shares (combiner verb, fanout cardinality, Lean anchor, stoplight count).
/// The test parses this header to verify cross-target alignment without
/// foreign-language execution.
pub fn manifest(fan: &Fanout) -> BTreeMap<String, String> {
    let mut m = BTreeMap::new();
    m.insert("verb".into(), fan.combiner.verb().into());
    m.insert("n".into(), fan.n.to_string());
    m.insert("op".into(), fan.op.clone());
    m.insert("lean_anchor".into(), fan.combiner.lean_anchor().into());
    m.insert("stoplights".into(), fan.stoplights.len().to_string());
    m.insert("chirality_marked".into(), fan.chirality.len().to_string());
    if let Combiner::Reduce(k) = &fan.combiner {
        m.insert("reduce_kernel".into(), k.verb().into());
    }
    if let Combiner::Drop { keep } = &fan.combiner {
        m.insert("drop_keep".into(), keep.to_string());
    }
    if let Combiner::Mix { weights } = &fan.combiner {
        m.insert(
            "mix_weights".into(),
            weights
                .iter()
                .map(|w| w.to_string())
                .collect::<Vec<_>>()
                .join(","),
        );
    }
    m
}

// -----------------------------------------------------------------------------
// Header helpers shared by every target. Each target embeds the manifest in a
// comment block so a structural grep (the test harness, or a human reader) can
// recover the IR shape from the emitted file.
// -----------------------------------------------------------------------------

fn header_lines(fan: &Fanout) -> Vec<String> {
    let m = manifest(fan);
    let mut lines = Vec::new();
    lines.push(format!("fanout: n={} op={}", fan.n, fan.op));
    lines.push(format!("combiner: {}", fan.combiner.verb()));
    lines.push(format!("lean: {}", fan.combiner.lean_anchor()));
    if let Some(k) = m.get("reduce_kernel") {
        lines.push(format!("reduce_kernel: {}", k));
    }
    if let Some(k) = m.get("drop_keep") {
        lines.push(format!("drop_keep: {}", k));
    }
    if let Some(w) = m.get("mix_weights") {
        lines.push(format!("mix_weights: {}", w));
    }
    if !fan.stoplights.is_empty() {
        lines.push(format!("stoplights: {}", fan.stoplights.len()));
        for (i, l) in fan.stoplights.iter().enumerate() {
            lines.push(format!(
                "stoplight[{}]: cycle={} green={} offset={} distance={} speed={}",
                i, l.cycle, l.green, l.offset, l.distance, l.speed
            ));
        }
    }
    if !fan.chirality.is_empty() {
        lines.push(format!(
            "chirality: {}",
            fan.chirality
                .iter()
                .map(|c| c.marker().to_string())
                .collect::<Vec<_>>()
                .join(",")
        ));
    }
    lines
}

fn comment_block<F: Fn(&str) -> String>(fan: &Fanout, line_fmt: F) -> String {
    header_lines(fan)
        .into_iter()
        .map(|l| line_fmt(&l))
        .collect::<Vec<_>>()
        .join("\n")
}

// -----------------------------------------------------------------------------
// Rust target: rayon parallel iterator.
// -----------------------------------------------------------------------------

fn lower_rust(fan: &Fanout) -> String {
    let header = comment_block(fan, |l| format!("// {}", l));
    let entry = format!("fanout_{}", fan.combiner.verb());
    // Idiomatic: rayon's into_par_iter + collect/find_any/reduce.
    let body = match &fan.combiner {
        Combiner::Collect => format!(
            "    (0..{n}).into_par_iter().map(op).collect::<Vec<i64>>()",
            n = fan.n
        ),
        Combiner::First => format!(
            "    (0..{n}).into_par_iter().map(op).find_any(|_| true).into_iter().collect::<Vec<i64>>()",
            n = fan.n
        ),
        Combiner::Reduce(k) => {
            let (ident, fold_op) = match k {
                ReduceKernel::Sum => ("0i64", "a.wrapping_add(b)"),
                ReduceKernel::Product => ("1i64", "a.wrapping_mul(b)"),
                ReduceKernel::Min => ("i64::MAX", "a.min(b)"),
                ReduceKernel::Max => ("i64::MIN", "a.max(b)"),
            };
            format!(
                "    let r = (0..{n}).into_par_iter().map(op).reduce(|| {ident}, |a, b| {fold_op});\n    vec![r]",
                n = fan.n
            )
        }
        Combiner::Drop { keep } => format!(
            "    let mut v = (0..{n}).into_par_iter().map(op).collect::<Vec<i64>>();\n    v.truncate({keep});\n    v",
            n = fan.n,
            keep = keep
        ),
        Combiner::Mix { weights } => {
            let weights_lit = weights
                .iter()
                .map(|w| format!("{}i64", w))
                .collect::<Vec<_>>()
                .join(", ");
            format!(
                "    let weights: [i64; {wn}] = [{ws}];\n    let sum_w: i64 = weights.iter().sum();\n    if sum_w == 0 {{ return vec![0]; }}\n    let acc: i128 = (0..{n}).into_par_iter().map(|i| (op(i) as i128) * (weights[i as usize % {wn}] as i128)).sum();\n    vec![(acc / sum_w as i128) as i64]",
                n = fan.n,
                wn = weights.len(),
                ws = weights_lit
            )
        }
    };
    format!(
        "{header}\nuse rayon::prelude::*;\n\npub fn {entry}<F: Fn(i64) -> i64 + Sync + Send>(op: F) -> Vec<i64> {{\n{body}\n}}\n"
    )
}

// -----------------------------------------------------------------------------
// JavaScript target: Promise.all (collect/fold/drop) / Promise.race (first).
// -----------------------------------------------------------------------------

fn lower_javascript(fan: &Fanout) -> String {
    let header = comment_block(fan, |l| format!("// {}", l));
    let entry = format!("fanout_{}", fan.combiner.verb());
    let body = match &fan.combiner {
        Combiner::Collect => format!(
            "  return await Promise.all(Array.from({{length: {n}}}, (_, i) => op(i)));",
            n = fan.n
        ),
        Combiner::First => format!(
            "  const r = await Promise.race(Array.from({{length: {n}}}, (_, i) => Promise.resolve(op(i))));\n  return [r];",
            n = fan.n
        ),
        Combiner::Reduce(k) => {
            let (ident, fold_op) = match k {
                ReduceKernel::Sum => ("0n", "a + b"),
                ReduceKernel::Product => ("1n", "a * b"),
                ReduceKernel::Min => ("9223372036854775807n", "a < b ? a : b"),
                ReduceKernel::Max => ("-9223372036854775808n", "a > b ? a : b"),
            };
            format!(
                "  const rs = await Promise.all(Array.from({{length: {n}}}, (_, i) => op(i)));\n  return [Number(rs.reduce((a, b) => {{ a = BigInt(a); b = BigInt(b); return {fold_op}; }}, {ident}))];",
                n = fan.n
            )
        }
        Combiner::Drop { keep } => format!(
            "  const rs = await Promise.all(Array.from({{length: {n}}}, (_, i) => op(i)));\n  return rs.slice(0, {keep});",
            n = fan.n,
            keep = keep
        ),
        Combiner::Mix { weights } => {
            let weights_lit = weights
                .iter()
                .map(|w| w.to_string())
                .collect::<Vec<_>>()
                .join(", ");
            format!(
                "  const weights = [{ws}];\n  const sumW = weights.reduce((a, b) => a + b, 0);\n  if (sumW === 0) return [0];\n  const rs = await Promise.all(Array.from({{length: {n}}}, (_, i) => op(i)));\n  const acc = rs.reduce((a, r, i) => a + BigInt(r) * BigInt(weights[i % weights.length]), 0n);\n  return [Number(acc / BigInt(sumW))];",
                n = fan.n,
                ws = weights_lit
            )
        }
    };
    format!("{header}\nexport async function {entry}(op) {{\n{body}\n}}\n")
}

// -----------------------------------------------------------------------------
// Elixir target: Task.async_stream / Task.async + Task.await_many.
// -----------------------------------------------------------------------------

fn lower_elixir(fan: &Fanout) -> String {
    let header = comment_block(fan, |l| format!("# {}", l));
    let entry = format!("fanout_{}", fan.combiner.verb());
    let body = match &fan.combiner {
        Combiner::Collect => format!(
            "    0..{last}\n    |> Enum.map(fn i -> Task.async(fn -> op.(i) end) end)\n    |> Task.await_many()",
            last = fan.n.saturating_sub(1)
        ),
        Combiner::First => format!(
            "    tasks = 0..{last} |> Enum.map(fn i -> Task.async(fn -> op.(i) end) end)\n    [r | _] = Task.await_many(tasks)\n    [r]",
            last = fan.n.saturating_sub(1)
        ),
        Combiner::Reduce(k) => {
            let (ident, fold_op) = match k {
                ReduceKernel::Sum => ("0", "a + b"),
                ReduceKernel::Product => ("1", "a * b"),
                ReduceKernel::Min => ("9_223_372_036_854_775_807", "min(a, b)"),
                ReduceKernel::Max => ("-9_223_372_036_854_775_808", "max(a, b)"),
            };
            format!(
                "    rs = 0..{last}\n      |> Enum.map(fn i -> Task.async(fn -> op.(i) end) end)\n      |> Task.await_many()\n    [Enum.reduce(rs, {ident}, fn b, a -> {fold_op} end)]",
                last = fan.n.saturating_sub(1)
            )
        }
        Combiner::Drop { keep } => format!(
            "    rs = 0..{last}\n      |> Enum.map(fn i -> Task.async(fn -> op.(i) end) end)\n      |> Task.await_many()\n    Enum.take(rs, {keep})",
            last = fan.n.saturating_sub(1),
            keep = keep
        ),
        Combiner::Mix { weights } => {
            let weights_lit = weights
                .iter()
                .map(|w| w.to_string())
                .collect::<Vec<_>>()
                .join(", ");
            format!(
                "    weights = [{ws}]\n    sum_w = Enum.sum(weights)\n    if sum_w == 0 do\n      [0]\n    else\n      rs = 0..{last}\n        |> Enum.map(fn i -> Task.async(fn -> op.(i) end) end)\n        |> Task.await_many()\n      acc = rs\n        |> Enum.with_index()\n        |> Enum.reduce(0, fn {{r, i}}, a -> a + r * Enum.at(weights, rem(i, length(weights))) end)\n      [div(acc, sum_w)]\n    end",
                last = fan.n.saturating_sub(1),
                ws = weights_lit
            )
        }
    };
    format!("{header}\ndefmodule Fanout do\n  def {entry}(op) do\n{body}\n  end\nend\n")
}

// -----------------------------------------------------------------------------
// Go target: goroutines + sync.WaitGroup.
// -----------------------------------------------------------------------------

fn lower_go(fan: &Fanout) -> String {
    let header = comment_block(fan, |l| format!("// {}", l));
    let entry = format!("Fanout{}", capitalize(fan.combiner.verb()));
    // Common: launch n goroutines, gather results into an indexed slice.
    let common_gather = format!(
        "\tresults := make([]int64, {n})\n\tvar wg sync.WaitGroup\n\twg.Add({n})\n\tfor i := 0; i < {n}; i++ {{\n\t\ti := i\n\t\tgo func() {{\n\t\t\tdefer wg.Done()\n\t\t\tresults[i] = op(int64(i))\n\t\t}}()\n\t}}\n\twg.Wait()\n",
        n = fan.n
    );
    let body = match &fan.combiner {
        Combiner::Collect => format!("{}\treturn results\n", common_gather),
        Combiner::First => format!(
            "\tch := make(chan int64, {n})\n\tfor i := 0; i < {n}; i++ {{\n\t\ti := i\n\t\tgo func() {{ ch <- op(int64(i)) }}()\n\t}}\n\treturn []int64{{<-ch}}\n",
            n = fan.n
        ),
        Combiner::Reduce(k) => {
            let (ident, fold_op) = match k {
                ReduceKernel::Sum => ("int64(0)", "acc + r"),
                ReduceKernel::Product => ("int64(1)", "acc * r"),
                ReduceKernel::Min => ("int64(math.MaxInt64)", "min64(acc, r)"),
                ReduceKernel::Max => ("int64(math.MinInt64)", "max64(acc, r)"),
            };
            format!(
                "{}\tacc := {ident}\n\tfor _, r := range results {{ acc = {fold_op} }}\n\treturn []int64{{acc}}\n",
                common_gather
            )
        }
        Combiner::Drop { keep } => format!(
            "{}\tif {keep} >= len(results) {{ return results }}\n\treturn results[:{keep}]\n",
            common_gather,
            keep = keep
        ),
        Combiner::Mix { weights } => {
            let weights_lit = weights
                .iter()
                .map(|w| format!("{}", w))
                .collect::<Vec<_>>()
                .join(", ");
            format!(
                "\tweights := []int64{{{ws}}}\n\tvar sumW int64\n\tfor _, w := range weights {{ sumW += w }}\n\tif sumW == 0 {{ return []int64{{0}} }}\n{}\tvar acc int64\n\tfor i, r := range results {{ acc += r * weights[i%len(weights)] }}\n\treturn []int64{{acc / sumW}}\n",
                common_gather,
                ws = weights_lit
            )
        }
    };
    let math_import = if matches!(
        &fan.combiner,
        Combiner::Reduce(ReduceKernel::Min | ReduceKernel::Max)
    ) {
        "\n\t\"math\""
    } else {
        ""
    };
    let helpers = if matches!(&fan.combiner, Combiner::Reduce(ReduceKernel::Min)) {
        "\nfunc min64(a, b int64) int64 { if a < b { return a }; return b }\n"
    } else if matches!(&fan.combiner, Combiner::Reduce(ReduceKernel::Max)) {
        "\nfunc max64(a, b int64) int64 { if a > b { return a }; return b }\n"
    } else {
        ""
    };
    format!(
        "{header}\npackage fanout\n\nimport (\n\t\"sync\"{math_import}\n)\n\nfunc {entry}(op func(int64) int64) []int64 {{\n{body}}}\n{helpers}"
    )
}

fn capitalize(s: &str) -> String {
    let mut c = s.chars();
    match c.next() {
        Some(first) => first.to_uppercase().collect::<String>() + c.as_str(),
        None => String::new(),
    }
}

// -----------------------------------------------------------------------------
// Python target: asyncio.gather / asyncio.wait FIRST_COMPLETED.
// -----------------------------------------------------------------------------

fn lower_python(fan: &Fanout) -> String {
    let header = comment_block(fan, |l| format!("# {}", l));
    let entry = format!("fanout_{}", fan.combiner.verb());
    let body = match &fan.combiner {
        Combiner::Collect => format!(
            "    rs = await asyncio.gather(*[op(i) for i in range({n})])\n    return list(rs)",
            n = fan.n
        ),
        Combiner::First => format!(
            "    done, pending = await asyncio.wait([asyncio.ensure_future(op(i)) for i in range({n})], return_when=asyncio.FIRST_COMPLETED)\n    for p in pending: p.cancel()\n    return [next(iter(done)).result()]",
            n = fan.n
        ),
        Combiner::Reduce(k) => {
            let (ident, fold_op) = match k {
                ReduceKernel::Sum => ("0", "a + b"),
                ReduceKernel::Product => ("1", "a * b"),
                ReduceKernel::Min => ("9223372036854775807", "min(a, b)"),
                ReduceKernel::Max => ("-9223372036854775808", "max(a, b)"),
            };
            format!(
                "    from functools import reduce\n    rs = await asyncio.gather(*[op(i) for i in range({n})])\n    return [reduce(lambda a, b: {fold_op}, rs, {ident})]",
                n = fan.n
            )
        }
        Combiner::Drop { keep } => format!(
            "    rs = await asyncio.gather(*[op(i) for i in range({n})])\n    return list(rs)[:{keep}]",
            n = fan.n,
            keep = keep
        ),
        Combiner::Mix { weights } => {
            let weights_lit = weights
                .iter()
                .map(|w| w.to_string())
                .collect::<Vec<_>>()
                .join(", ");
            format!(
                "    weights = [{ws}]\n    sum_w = sum(weights)\n    if sum_w == 0: return [0]\n    rs = await asyncio.gather(*[op(i) for i in range({n})])\n    acc = sum(r * weights[i % len(weights)] for i, r in enumerate(rs))\n    return [acc // sum_w]",
                n = fan.n,
                ws = weights_lit
            )
        }
    };
    format!("{header}\nimport asyncio\n\nasync def {entry}(op):\n{body}\n")
}

#[cfg(test)]
mod tests {
    use super::*;

    fn stub_op(i: i64) -> i64 {
        i + 1
    }

    #[test]
    fn collect_oracle_matches_reference() {
        let results: Vec<i64> = (0..5).map(stub_op).collect();
        let out = apply_combiner(&Combiner::Collect, &results);
        assert_eq!(out, vec![1, 2, 3, 4, 5]);
    }

    #[test]
    fn reduce_sum_oracle() {
        let results: Vec<i64> = (0..5).map(stub_op).collect();
        let out = apply_combiner(&Combiner::Reduce(ReduceKernel::Sum), &results);
        assert_eq!(out, vec![15]);
    }

    #[test]
    fn drop_keeps_prefix() {
        let results: Vec<i64> = (0..5).map(stub_op).collect();
        let out = apply_combiner(&Combiner::Drop { keep: 2 }, &results);
        assert_eq!(out, vec![1, 2]);
    }

    #[test]
    fn mix_weighted_average() {
        let results = vec![10, 20, 30];
        let out = apply_combiner(
            &Combiner::Mix {
                weights: vec![1, 1, 1],
            },
            &results,
        );
        assert_eq!(out, vec![20]);
    }

    #[test]
    fn mix_zero_weights_returns_identity() {
        let results = vec![10, 20, 30];
        let out = apply_combiner(
            &Combiner::Mix {
                weights: vec![0, 0, 0],
            },
            &results,
        );
        assert_eq!(out, vec![0]);
    }

    #[test]
    fn every_target_lowers_every_combiner() {
        let cases = vec![
            Fanout::fork(4, "load"),
            Fanout::race(4, "load"),
            Fanout::fold(4, "load", ReduceKernel::Sum),
            Fanout::vent(4, "load", 2),
            Fanout::interfere(4, "load", vec![1, 1, 1, 1]),
        ];
        for fan in &cases {
            for tgt in Target::all() {
                let src = lower(fan, *tgt);
                assert!(
                    src.contains(fan.combiner.verb()),
                    "target {:?} did not emit combiner verb {} for {:?}",
                    tgt,
                    fan.combiner.verb(),
                    fan.combiner
                );
                assert!(
                    src.contains(fan.combiner.lean_anchor()),
                    "target {:?} did not cite lean anchor",
                    tgt
                );
                assert!(
                    src.contains(&fan.n.to_string()),
                    "target {:?} did not emit cardinality {}",
                    tgt,
                    fan.n
                );
            }
        }
    }

    #[test]
    fn stoplight_metadata_emitted_in_each_target() {
        let fan = Fanout::fork(2, "op").with_stoplights(vec![
            Stoplight {
                cycle: 100,
                green: 30,
                offset: 0,
                distance: 50,
                speed: 1,
            },
            Stoplight {
                cycle: 100,
                green: 30,
                offset: 35,
                distance: 50,
                speed: 1,
            },
        ]);
        for tgt in Target::all() {
            let src = lower(&fan, *tgt);
            assert!(
                src.contains("stoplight[0]"),
                "target {:?} dropped stoplight metadata",
                tgt
            );
            assert!(src.contains("cycle=100"));
        }
    }
}
